#include<cstdio>
#include<map>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
#define int LL
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int fa[N],n,m,W,idx[N],t[N],w[N];
std::map<int,int> dp[N];
inline int merge(int a,int b)
{
	if(dp[a].size()<dp[b].size()){int tmp=a;a=b;b=tmp;}
	for(auto v: dp[b])dp[a][v.first]+=v.second;return a;
}
signed main()
{
	n=read();m=read();W=read();rep(2,n,i)fa[i]=read();
	rep(1,m,i){int x=read();t[x]=read();w[x]=read();} rep(1,n,i)idx[i]=i;
	drep(n,1,i)
	{
		
		dp[idx[i]][t[i]]+=w[i];
		auto v=dp[idx[i]].find(t[i]);++v;
		for(;v!=dp[idx[i]].end();)
		{
			if(v->second>w[i]){v->second-=w[i];break;}
			w[i]-=v->second;auto tmp=v;++v;dp[idx[i]].erase(tmp);
		}
		idx[fa[i]]=merge(idx[fa[i]],idx[i]);
	}
	long long ans=0;for(auto v: dp[idx[1]]) ans+=v.second;printf("%lld\n",ans);
}
